const slug = $input.first().json.query.slug;
if (!slug || slug.trim() === '') {
  return [{ json: { _valid: false, error: 'Missing or empty slug parameter' } }];
}
const clean = slug.trim().toLowerCase();
if (!/^[a-z0-9-]+$/.test(clean)) {
  return [{ json: { _valid: false, error: 'Invalid slug format' } }];
}
return [{ json: { _valid: true, slug: clean } }];

const row = $input.first().json;
const config = typeof row.config === 'string' ? JSON.parse(row.config) : (row.config ?? {});
const staticStats = config.stats ?? {};
const templates = typeof row.action_templates === 'string' ? JSON.parse(row.action_templates) : (row.action_templates ?? {});
const quickActions = (config.quick_actions ?? []).map(action => ({
  key: action.key,
  label: action.label,
  prompt: action.prompt_override ?? templates[action.key] ?? action.prompt ?? ''
}));
return [{
  json: {
    slug: row.slug,
    name: row.name,
    branding: config.branding ?? {},
    features: (typeof row.features === 'string' ? JSON.parse(row.features) : row.features) ?? {},
    quick_actions: quickActions,
    workflows: config.workflows ?? [],
    stats: {
      ai_conversations_week: row.ai_conversations_week ?? staticStats.ai_conversations_week ?? 0,
      automations_last_24h: row.automations_last_24h ?? 0,
      documents_indexed: row.documents_indexed ?? 0,
      active_users: row.active_users ?? 0,
      seat_limit: staticStats.seat_limit ?? 5,
      hours_saved_yesterday: staticStats.hours_saved_yesterday ?? 0,
    }
  }
}];
